// Coins available: 25, 10, 5, 1
// Make 41 cents using the FEWEST coins possible

// Greedy: always take the LARGEST coin that still fits
// 41 -> take 25 (16 left) -> take 10 (6 left) -> take 5 (1 left) -> take 1 (0 left)
// Total: 4 coins

#include <iostream>
#include <vector>

using namespace std;

int minCoins(vector<int> &coins, int amount)
{
    int count = 0;

    for (int i = 0; i < coins.size(); i++) // coins assumed sorted LARGEST to smallest
    {
        while (amount >= coins[i])
        {
            amount -= coins[i]; // take this coin greedily, as many times as fits
            count++;
        }
    }
    return count;
}

int main()
{
    vector<int> coins = {25, 10, 5, 1};

    cout << minCoins(coins, 41) << endl;

    return 0;
}

// Coins available: 4, 3, 1 — a DIFFERENT, non-standard coin system
// Make 6 cents using the FEWEST coins possible

// Greedy: take 4 (largest that fits) -> 2 left -> no 4 or 3 fits -> take 1, 1 -> total 3 coins (4+1+1)
// But the ACTUAL best answer is 3+3 -> only 2 coins!

