#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int findContentChildren(vector<int>& g, vector<int>& s)
{
    sort(g.begin(), g.end());
    sort(s.begin(), s.end());

    vector<bool> used(s.size(), false);
    int content = 0;

    for (int need : g)
    {
        int bestIndex = -1;
        for (int j = 0; j < (int)s.size(); j++)
            if (!used[j] && s[j] >= need)
            {
                if (bestIndex == -1 || s[j] < s[bestIndex]) bestIndex = j;
            }
        if (bestIndex != -1)
        {
            used[bestIndex] = true;
            content++;
        }
    }
    return content;
}

int main()
{
    vector<int> g = {1, 2, 3};
    vector<int> s = {1, 1};

    cout << findContentChildren(g, s);

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int findContentChildren(vector<int>& g, vector<int>& s)
{
    sort(g.begin(), g.end());
    sort(s.begin(), s.end());

    int child = 0, cookie = 0;
    while (child < (int)g.size() && cookie < (int)s.size())
    {
        if (s[cookie] >= g[child]) child++;
        cookie++;
    }
    return child;
}

int main()
{
    vector<int> g = {1, 2, 3};
    vector<int> s = {1, 1};

    cout << findContentChildren(g, s);

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int maxProfit(vector<int>& prices)
{
    int best = 0;
    for (int buy = 0; buy < (int)prices.size(); buy++)
        for (int sell = buy + 1; sell < (int)prices.size(); sell++)
            best = max(best, prices[sell] - prices[buy]);
    return best;
}

int main()
{
    vector<int> prices = {7, 1, 5, 3, 6, 4};
    cout << maxProfit(prices);

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int maxProfit(vector<int>& prices)
{
    int minPriceSoFar = INT_MAX;
    int maxProfitSoFar = 0;

    for (int price : prices)
    {
        minPriceSoFar = min(minPriceSoFar, price);
        maxProfitSoFar = max(maxProfitSoFar, price - minPriceSoFar);
    }

    return maxProfitSoFar;
}

int main()
{
    vector<int> prices = {7, 1, 5, 3, 6, 4};
    cout << maxProfit(prices);

    return 0;
}

